import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat format;

    @BeforeEach
    void setUp() {
        format = mock(CSVFormat.class);
    }

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String input = "header1,header2\nvalue1,value2";
        try (MockedStatic<Assertions> assertionsMock = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull does nothing (void), so no action needed on mock
            CSVParser parser = CSVParser.parse(input, format);
            assertNotNull(parser);
            // The parser should use a StringReader internally (cannot access directly)
            // Just verify that the format is set correctly via reflection
            var formatField = CSVParser.class.getDeclaredField("format");
            formatField.setAccessible(true);
            CSVFormat actualFormat = (CSVFormat) formatField.get(parser);
            assertSame(format, actualFormat);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Reflection failed: " + e.getMessage());
        }
    }

    @Test
    void testParse_withNullString_throwsException() {
        try (MockedStatic<Assertions> assertionsMock = Mockito.mockStatic(Assertions.class)) {
            assertionsMock.when(() -> Assertions.notNull(null, "string"))
                    .thenThrow(new IllegalArgumentException("string must not be null"));
            IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
                CSVParser.parse(null, format);
            });
            assertEquals("string must not be null", thrown.getMessage());
        }
    }

    @Test
    void testParse_withNullFormat_throwsException() {
        String input = "a,b,c";
        try (MockedStatic<Assertions> assertionsMock = Mockito.mockStatic(Assertions.class)) {
            assertionsMock.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            assertionsMock.when(() -> Assertions.notNull(null, "format"))
                    .thenThrow(new IllegalArgumentException("format must not be null"));
            IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
                CSVParser.parse(input, null);
            });
            assertEquals("format must not be null", thrown.getMessage());
        }
    }
}
